// ╔══════════════════════════════════════════════════╗
// ║  MODULE 0: CENTRAL CONFIG                        ║
// ║  Edit ONLY this node for all settings.           ║
// ╚══════════════════════════════════════════════════╝
const CONFIG = {
  user_email:       'maherahmedraza1@gmail.com',
  backfill_after:   '2025/10/01',
  backfill_before:  '2026/04/05',

  // Valid models:
  // gemini-3.1-flash-lite-preview  (cheapest, fast)
  // gemini-3-flash-preview         (better)
  // gemini-3.1-pro-preview         (best)
  // gemini-1.5-flash-8b            (stable fallback)
  gemini_model:      'gemini-3.1-flash-lite-preview',
  thinking_level:    'minimal',
  gemini_batch_size: 10,
  batch_delay_ms:    2000,
  min_confidence:    0.55,

  telegram_enabled:   false,
  telegram_bot_token: '',
  telegram_chat_id:   '',

  blocked_senders_exact: [
    'notifications-noreply@linkedin.com','jobs-listings@linkedin.com',
    'jobs-noreply@linkedin.com','jobalerts-noreply@linkedin.com',
    'inmail-hit-reply@linkedin.com','updates-noreply@linkedin.com',
    'messages-noreply@linkedin.com','learning-noreply@linkedin.com',
    'news-noreply@linkedin.com','premium-noreply@linkedin.com',
    'news@mail.xing.com','info@jobagent.stepstone.de',
    'jobalert@indeed.com','alert@indeed.com','noreply@indeed.com',
    'hello@dataquest.io','stefan.huber@hokify.com','noreply@arbeitsagentur.de'
  ],
  sender_block_patterns: [
    'jobalerts-noreply@','jobs-listings@linkedin',
    'notifications-noreply@linkedin','updates-noreply@linkedin',
    'messages-noreply@linkedin','learning-noreply@linkedin',
    'news-noreply@linkedin','premium-noreply@linkedin',
    'jobagent@stepstone','jobagent@indeed',
    '@hokify.com','noreply@newsletter.','jobalert@','job-alert@'
  ],
  university_patterns: ['uni-koblenz.de','list.uni-','studierende@','@asta.'],
  subject_always_exclude: [
    'new jobs for you','neue jobs für dich','jobs matching your search',
    'jobs you might like','job recommendations','new jobs in your area',
    'companies are looking for candidates like you',
    'read this article','read on linkedin','published a newsletter',
    'published an article','started a new position','is celebrating',
    'has a new job','people viewed your profile','search appearances',
    'your posts got','impressions last week','top voices','trending on linkedin',
    'weekly digest','monthly digest','connection digest','weekly roundup',
    'career tips','karrieretipps','job alert','job-alert','jobalert',
    'new jobs matching','jobs matching your','10+ new jobs','5+ new jobs',
    'jobbenachrichtigung','job benachrichtigung','you have 1 new invitation',
    'asta sitzung','vorlesung','tutorium','klausur',
    'spannende jobs für dich','ich denke diese jobs passen','system migration',
    'one-time-passcode','one-time password','passcode','verification code',
    'bestätigungscode','ihr zugangscode','dein zugangscode',
    'complete your application','finish your application','bewerbung abschließen'
  ]
};

// Detect whether this was triggered by Gmail or manually
let runMode = 'manual_backfill';
let emailData = null;
try {
  const t = $('Gmail Trigger').first().json;
  if (t && t.id) { runMode = 'email_trigger'; emailData = t; }
} catch(e) {}

console.log(`🚀 Run mode: ${runMode}`);
return [{ json: { runMode, emailData, config: CONFIG, triggeredAt: new Date().toISOString() } }];

const drive  = $input.first().json;
const cfg    = $('⚙️ CONFIG').first().json;
const fileId = drive.files?.[0]?.id || null;
console.log(fileId ? `✅ Sheet found: ${fileId}` : '📋 No sheet - will create');
return [{ json: {
  sheetExists:    !!fileId,
  spreadsheetId:  fileId,
  runMode:        cfg.runMode,
  emailData:      cfg.emailData,
  config:         cfg.config,
  triggeredAt:    cfg.triggeredAt
} }];

const meta = $input.first().json;
const prev = $('📋 Resolve Sheet').first().json;
let appId=null, dashId=null, logId=null;
for (const s of (meta.sheets||[])) {
  const p = s.properties||{};
  if (p.title==='Applications')       appId  = String(p.sheetId);
  if (p.title==='Dashboard')          dashId = String(p.sheetId);
  if (p.title==='Classification Log') logId  = String(p.sheetId);
}
console.log(`Tabs: App=${appId} Dash=${dashId} Log=${logId}`);
return [{ json: { ...prev, spreadsheetId: prev.spreadsheetId, applicationsSheetId: appId, dashboardSheetId: dashId, logSheetId: logId, isNewSheet: false } }];

const c    = $input.first().json;
const prev = $('📋 Resolve Sheet').first().json;
const sh   = c.sheets||[];
let appId=null, dashId=null, logId=null;
for (const s of sh) {
  const p=s.properties||{};
  if (p.title==='Applications')       appId  = String(p.sheetId);
  if (p.title==='Dashboard')          dashId = String(p.sheetId);
  if (p.title==='Classification Log') logId  = String(p.sheetId);
}
if (!appId  && sh[0]) appId  = String(sh[0].properties.sheetId);
if (!dashId && sh[1]) dashId = String(sh[1].properties.sheetId);
if (!logId  && sh[2]) logId  = String(sh[2].properties.sheetId);
return [{ json: { ...prev, spreadsheetId: c.spreadsheetId, applicationsSheetId: appId, dashboardSheetId: dashId, logSheetId: logId, isNewSheet: true } }];

// ╔══════════════════════════════════════════════════════════════╗
// ║  MODULE 3: GMAIL FETCH + COLLECT (THE KEY FIX)               ║
// ║                                                              ║
// ║  THE PROBLEM with previous version:                          ║
// ║  Build Queries → outputs 6 items (months)                    ║
// ║  Fetch node → runs 6 times, each outputs N emails            ║
// ║  Dedup node → triggered N*6 times (once per email!)          ║
// ║  = INFINITE LOOP                                             ║
// ║                                                              ║
// ║  THE FIX:                                                    ║
// ║  This single Code node does ALL of:                          ║
// ║  1. Build monthly queries                                    ║
// ║  2. Call Gmail API directly (HTTP) for each month            ║
// ║  3. Collect ALL results into one array                       ║
// ║  4. Deduplicate by email ID                                  ║
// ║  5. Filter against cache                                     ║
// ║  6. Return one item per new email                            ║
// ║                                                              ║
// ║  One node in → N emails out (controlled, predictable)        ║
// ╚══════════════════════════════════════════════════════════════╝

const data   = $input.first().json;
const config = data.config;

// ── Build date-chunked queries ────────────────────────────────
const BLOCKED_FROM = [
  'jobalerts-noreply@linkedin.com','info@jobagent.stepstone.de',
  'jobalert@indeed.com','alert@indeed.com','noreply@indeed.com','news@mail.xing.com'
].map(s => `-from:${s}`).join(' ');

const KEYWORDS = '(bewerbung OR application OR absage OR rejection OR einladung OR interview OR eingangsbestätigung OR eingangsbestaetigung OR angebot OR "ihre bewerbung" OR "deine bewerbung" OR "thank you for applying" OR "we received")';

const after  = config.backfill_after  || '2025/10/01';
const before = config.backfill_before || '2026/04/05';
const [ay, am] = after.split('/').map(Number);
const [by, bm] = before.split('/').map(Number);

const queries = [];
let cy = ay, cm = am;
while (cy < by || (cy === by && cm <= bm)) {
  const ca = `${cy}/${String(cm).padStart(2,'0')}/01`;
  let ny = cy, nm = cm + 1;
  if (nm > 12) { nm = 1; ny++; }
  const cb = (ny > by || (ny === by && nm > bm)) ? before : `${ny}/${String(nm).padStart(2,'0')}/01`;
  queries.push({ label: `${cy}-${String(cm).padStart(2,'0')}`, q: `${KEYWORDS} ${BLOCKED_FROM} after:${ca} before:${cb}` });
  cy = ny; cm = nm;
  if (cy > by || (cy === by && cm > bm)) break;
}
console.log(`📅 ${queries.length} monthly queries: ${after} → ${before}`);

// ── Fetch all months via Gmail API ────────────────────────────
// We use $http (n8n's built-in HTTP helper with OAuth)
// This keeps it in ONE node so output is controlled
const allEmails = [];
const seenIds = new Set();

for (const chunk of queries) {
  console.log(`  Fetching [${chunk.label}]: ${chunk.q.substring(0, 80)}...`);

  try {
    let pageToken = null;
    let pageCount = 0;
    let chunkCount = 0;

    // Paginate through all results for this month
    do {
      const params = new URLSearchParams({ q: chunk.q, maxResults: '500', format: 'full' });
      if (pageToken) params.set('pageToken', pageToken);

      const resp = await $http.request({
        method: 'GET',
        url: `https://gmail.googleapis.com/gmail/v1/users/me/messages?${params.toString()}`,
        authentication: 'predefinedCredentialType',
        nodeCredentialType: 'gmailOAuth2'
      });

      const messages = resp.messages || [];
      pageToken = resp.nextPageToken || null;
      pageCount++;

      // Fetch full details for each message
      for (const msg of messages) {
        if (seenIds.has(msg.id)) continue;
        seenIds.add(msg.id);

        try {
          const detail = await $http.request({
            method: 'GET',
            url: `https://gmail.googleapis.com/gmail/v1/users/me/messages/${msg.id}?format=full`,
            authentication: 'predefinedCredentialType',
            nodeCredentialType: 'gmailOAuth2'
          });
          allEmails.push(detail);
          chunkCount++;
        } catch(detailErr) {
          console.warn(`  ⚠️ Failed to fetch details for ${msg.id}: ${detailErr.message}`);
        }
      }

      if (messages.length === 0) break;
    } while (pageToken && pageCount < 5); // Max 5 pages per month (2500 emails)

    console.log(`  ✅ [${chunk.label}]: ${chunkCount} emails fetched`);
  } catch(err) {
    console.error(`  ❌ [${chunk.label}] fetch failed: ${err.message}`);
  }
}

console.log(`📥 Total fetched: ${allEmails.length} unique emails across all months`);

// ── Filter against processed cache ───────────────────────────
const cache = $getWorkflowStaticData('global');
if (!cache.processedEmailIds) cache.processedEmailIds = {};

// Clean cache entries older than 90 days
const cutoff = Date.now() - (90 * 24 * 60 * 60 * 1000);
let cleaned = 0;
for (const [id, ts] of Object.entries(cache.processedEmailIds)) {
  if (typeof ts === 'number' && ts < cutoff) { delete cache.processedEmailIds[id]; cleaned++; }
}
if (cleaned > 0) console.log(`🗑️ Cache: cleaned ${cleaned} expired entries`);
console.log(`📦 Cache: ${Object.keys(cache.processedEmailIds).length} entries`);

const newEmails = allEmails.filter(e => !cache.processedEmailIds[e.id]);
console.log(`🆕 New emails to process: ${newEmails.length} (${allEmails.length - newEmails.length} already cached)`);

if (newEmails.length === 0) {
  return [{ json: {
    spreadsheetId: data.spreadsheetId,
    logSheetId:    String(data.logSheetId || ''),
    config:        data.config,
    noEmails:      true,
    reason:        `All ${allEmails.length} emails already processed`
  } }];
}

// ── Return one item per new email ─────────────────────────────
return newEmails.map(email => ({ json: {
  spreadsheetId:       data.spreadsheetId,
  logSheetId:          String(data.logSheetId || ''),
  applicationsSheetId: String(data.applicationsSheetId || ''),
  config:              data.config,
  email
} }));

// Handle single email from Gmail Trigger
const sheetInfo = $('🔀 Merge Sheet Ready').first().json;
const email     = sheetInfo.emailData;
if (!email) {
  return [{ json: { spreadsheetId: sheetInfo.spreadsheetId, logSheetId: String(sheetInfo.logSheetId||''), applicationsSheetId: String(sheetInfo.applicationsSheetId||''), config: sheetInfo.config, noEmails: true, reason: 'No email from trigger' } }];
}
console.log(`📧 Single trigger email: ${email.id}`);
return [{ json: { spreadsheetId: sheetInfo.spreadsheetId, logSheetId: String(sheetInfo.logSheetId||''), applicationsSheetId: String(sheetInfo.applicationsSheetId||''), config: sheetInfo.config, email } }];

// ╔══════════════════════════════════════════════════════╗
// ║  MODULE 5: PRE-FILTER                                ║
// ║  Rule-based filter before spending Gemini tokens.    ║
// ╚══════════════════════════════════════════════════════╝
const passed = [], filtered = [];
let stats = { total:0, sender:0, subject:0, uni:0, self:0, passed:0 };

for (const item of $input.all()) {
  const d = item.json;
  if (!d.email || d.noEmails) continue;
  stats.total++;
  const email = d.email;
  const cfg   = d.config || {};

  // Extract subject
  const subject = (
    email.subject ||
    (email.payload?.headers||[]).find(h=>h.name?.toLowerCase()==='subject')?.value ||
    ''
  ).toLowerCase().trim();

  // Extract sender from Gmail API payload headers
  let fromEmail = '', fromRaw = '';
  const fromHeader = (email.payload?.headers||[]).find(h=>h.name?.toLowerCase()==='from');
  if (fromHeader) {
    fromRaw = fromHeader.value || '';
    const m = fromRaw.match(/<([^>]+)>/);
    fromEmail = (m ? m[1] : fromRaw).toLowerCase().trim();
  }

  const block = (reason) => { filtered.push({ reason, from: fromEmail, subject: subject.substring(0,60) }); };

  // 1. Exact blocked senders
  if ((cfg.blocked_senders_exact||[]).some(s => fromEmail === s.toLowerCase())) {
    stats.sender++; block('exact_sender'); continue;
  }
  // 2. Sender patterns
  if ((cfg.sender_block_patterns||[]).some(p => fromEmail.includes(p.toLowerCase()))) {
    stats.sender++; block('pattern_sender'); continue;
  }
  // 3. Self-sent
  if ((cfg.user_email||'').toLowerCase() === fromEmail) {
    stats.self++; block('self_sent'); continue;
  }
  // 4. Subject exclusions
  const badSubj = (cfg.subject_always_exclude||[]).find(kw => subject.includes(kw.toLowerCase()));
  if (badSubj) {
    stats.subject++; block(`subject:"${badSubj.substring(0,30)}"`); continue;
  }
  // 5. University (unless job keyword in subject)
  if ((cfg.university_patterns||[]).some(p => fromEmail.includes(p.toLowerCase()))) {
    const jobKw = ['bewerbung','application','absage','rejection','eingangsbestätigung','thank you for applying'];
    if (!jobKw.some(k => subject.includes(k))) {
      stats.uni++; block('university'); continue;
    }
  }

  stats.passed++;
  passed.push({ json: { ...d, _fromEmail: fromEmail, _fromRaw: fromRaw } });
}

console.log(`🚫 Pre-filter: ${stats.passed}/${stats.total} passed | Blocked: sender=${stats.sender} subject=${stats.subject} uni=${stats.uni} self=${stats.self}`);
if (filtered.length > 0) {
  console.log('Filtered (first 10):');
  filtered.slice(0,10).forEach((e,i) => console.log(`  ${i+1}. [${e.reason}] "${e.subject}" | ${e.from}`));
}

if (passed.length === 0) {
  const f = $input.first()?.json||{};
  return [{ json: { spreadsheetId:f.spreadsheetId, logSheetId:f.logSheetId, config:f.config, noEmails:true, reason:`All ${stats.total} filtered` } }];
}
return passed;

// ╔══════════════════════════════════════════════════════════╗
// ║  MODULE 6: GEMINI BATCH BUILDER                          ║
// ╚══════════════════════════════════════════════════════════╝
const allItems = $input.all().filter(i => !i.json.noEmails && i.json.email);
if (allItems.length === 0) return [{ json: { noBatches: true } }];

const cfg        = allItems[0].json.config || {};
const BATCH_SIZE = cfg.gemini_batch_size || 10;
const MODEL      = cfg.gemini_model || 'gemini-3.1-flash-lite-preview';
const DELAY      = cfg.batch_delay_ms || 2000;
const THINKING   = cfg.thinking_level || 'minimal';
const MAX_BODY   = 800;

function extractBody(email) {
  // Try plain text from Gmail API payload
  const findText = (parts) => {
    if (!parts) return '';
    for (const p of parts) {
      if (p.mimeType === 'text/plain' && p.body?.data) {
        try { return Buffer.from(p.body.data, 'base64').toString('utf-8').substring(0, MAX_BODY); } catch(e) {}
      }
      const r = findText(p.parts); if (r) return r;
    }
    return '';
  };
  const fromParts = findText(email.payload?.parts);
  if (fromParts) return fromParts;
  if (email.payload?.body?.data) {
    try { return Buffer.from(email.payload.body.data, 'base64').toString('utf-8').substring(0, MAX_BODY); } catch(e) {}
  }
  return (email.snippet || '').substring(0, MAX_BODY);
}

function extractMeta(item) {
  const email    = item.json.email || {};
  const headers  = email.payload?.headers || [];
  const getH     = (name) => headers.find(h => h.name?.toLowerCase() === name.toLowerCase())?.value || '';
  const emailId  = email.id || '';
  const threadId = email.threadId || '';
  const subject  = getH('Subject').trim();
  const from     = item.json._fromRaw || getH('From');
  const dateStr  = getH('Date');
  const internalDate = email.internalDate;
  let parsedDate = new Date().toISOString().split('T')[0];
  try {
    if (/^\d{13}$/.test(String(internalDate))) parsedDate = new Date(parseInt(internalDate)).toISOString().split('T')[0];
    else if (dateStr) { const d = new Date(dateStr); if (!isNaN(d)) parsedDate = d.toISOString().split('T')[0]; }
  } catch(e) {}
  return {
    emailId, threadId, subject, from, parsedDate,
    body: extractBody(email),
    spreadsheetId:       item.json.spreadsheetId,
    logSheetId:          item.json.logSheetId,
    applicationsSheetId: item.json.applicationsSheetId,
    config:              item.json.config
  };
}

const batches = [];
for (let i = 0; i < allItems.length; i += BATCH_SIZE) batches.push(allItems.slice(i, i + BATCH_SIZE));
console.log(`📦 ${allItems.length} emails → ${batches.length} batches | Model: ${MODEL}`);

return batches.map((batchItems, batchIdx) => {
  const metas = batchItems.map((item, idx) => ({ index: idx, ...extractMeta(item) }));
  const emailsText = metas.map((m,i) =>
    `=== EMAIL ${i+1} ===\nSubject: ${m.subject}\nFrom: ${m.from}\nDate: ${m.parsedDate}\nBody:\n${m.body||'(empty)'}`
  ).join('\n\n---\n\n');

  const prompt = `You are a job application email classifier for a German job seeker.
Classify each email. Return ONLY valid JSON, no markdown.

TYPES:
1. "application_confirmation" - Company confirmed receiving YOUR application
   Signals: Eingangsbestätigung, Bewerbung erhalten, Vielen Dank für Ihre/deine Bewerbung,
   we received your application, Your Application - [Title], Deine Bewerbung bei [Co],
   wir haben Ihre Unterlagen erhalten, application confirmed, successfully submitted

2. "rejection" - Application declined
   Signals: leider absagen, leider müssen wir, andere Kandidaten, unfortunately,
   cannot offer, unable to proceed, nicht berücksichtigen, we regret,
   decided to move forward with other candidates

3. "positive_response" - Interview invite, assessment, offer
   Signals: einladen, Vorstellungsgespräch, Kennenlerngespräch, assessment,
   we would like to invite, next steps, please schedule

4. "not_job_related" - Everything else (alerts, newsletters, OTPs, marketing)

EXTRACTION RULES:
- company_name: HIRING company, NOT the ATS platform
  * "Bosch Group <notifications@smartrecruiters.com>" → "Robert Bosch GmbH"
  * "HR <e113-jobs@m.personio.de>" → extract from body or use email prefix
  * "anna@dekra.com" → "DEKRA"
  * NEVER use: SmartRecruiters, Personio, Workday, Lever, Greenhouse, Workwise, Onlyfy
- job_title: Exact title or "Not Specified"
- platform: smartrecruiters.com→SmartRecruiters, m.personio.de→Personio,
  workday.com→Workday, lever.co→Lever, greenhouse.io→Greenhouse,
  successfactors.com/eu→SAP SuccessFactors, softgarden.io→Softgarden,
  onlyfy.jobs→Onlyfy, workwise.io→Workwise, recruitee.com→Recruitee,
  own domain→Direct, unknown→Direct
- confidence: 0.9+=clear, 0.7-0.89=likely, 0.55-0.69=uncertain, <0.55→not_job_related

EMAILS:
${emailsText}

{"results":[{"email_index":1,"classification":"application_confirmation","company_name":"Company","job_title":"Title or Not Specified","platform":"Platform","confidence":0.95,"reasoning":"Brief"}]}`;

  const isGemini3 = MODEL.startsWith('gemini-3');
  const generationConfig = {
    temperature: 0.05,
    maxOutputTokens: Math.max(1500, batchItems.length * 300),
    responseMimeType: 'application/json'
  };
  if (isGemini3 && THINKING) {
    generationConfig.thinkingConfig = { thinking_level: THINKING };
  }

  return { json: {
    batchIndex: batchIdx,
    totalBatches: batches.length,
    emailCount: batchItems.length,
    emailMetas: metas,
    model: MODEL,
    delayMs: batchIdx > 0 ? DELAY : 0,
    geminiRequest: {
      contents: [{ parts: [{ text: prompt }] }],
      generationConfig,
      safetySettings: [
        { category:'HARM_CATEGORY_HARASSMENT',       threshold:'BLOCK_NONE' },
        { category:'HARM_CATEGORY_HATE_SPEECH',       threshold:'BLOCK_NONE' },
        { category:'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold:'BLOCK_NONE' },
        { category:'HARM_CATEGORY_DANGEROUS_CONTENT', threshold:'BLOCK_NONE' }
      ]
    }
  } };
});

const input = $input.first().json;
if (input.delayMs > 0) {
  console.log(`⏳ Delay ${input.delayMs}ms before batch ${input.batchIndex+1}/${input.totalBatches}`);
  await new Promise(r => setTimeout(r, input.delayMs));
}
console.log(`📤 Batch ${input.batchIndex+1}/${input.totalBatches} | ${input.emailCount} emails`);
return [$input.first()];

// ╔══════════════════════════════════════════════════════╗
// ║  MODULE 7: RESULT EXPANDER                           ║
// ╚══════════════════════════════════════════════════════╝
const batchMeta = $('⏱️ Delay').first().json;
const resp      = $input.first().json;
const cache     = $getWorkflowStaticData('global');
if (!cache.processedEmailIds) cache.processedEmailIds = {};

const mark = (id) => { if (id) cache.processedEmailIds[id] = Date.now(); };

const errResult = (meta, msg) => {
  mark(meta.emailId);
  return { json: {
    spreadsheetId: meta.spreadsheetId, logSheetId: String(meta.logSheetId||''),
    applicationsSheetId: String(meta.applicationsSheetId||''), config: meta.config,
    is_job_related: false, classification: 'api_error',
    company_name: 'Error', job_title: 'Error', platform: 'Unknown',
    status: '', confidence: 0, error: msg.substring(0,300), reasoning: msg.substring(0,200),
    email_subject: meta.subject, email_from: meta.from,
    email_date: meta.parsedDate, emailId: meta.emailId, threadId: meta.threadId
  } };
};

if (!batchMeta?.emailMetas) return [{ json:{is_job_related:false,classification:'parse_error',company_name:'Error',job_title:'Error',platform:'Unknown',status:'',confidence:0} }];

if (resp.error) {
  const msg = `Gemini Error ${resp.error.code}: ${resp.error.message||'Unknown'}`;
  console.error(`❌ ${msg}`);
  return batchMeta.emailMetas.map(m => errResult(m, msg));
}

// Extract text (skip thinking parts)
let content = '';
for (const part of (resp.candidates?.[0]?.content?.parts||[])) {
  if (part.thought === true) continue;
  if (part.text) { content = part.text; break; }
}
if (!content) content = resp.candidates?.[0]?.content?.parts?.[0]?.text || '';
if (!content) return batchMeta.emailMetas.map(m => errResult(m, 'Empty Gemini response'));

// Parse JSON
content = content.replace(/```json\s*/g,'').replace(/```\s*/g,'').trim();
const fb = content.indexOf('{'), lb = content.lastIndexOf('}');
if (fb===-1||lb===-1) return batchMeta.emailMetas.map(m => errResult(m, `No JSON: ${content.substring(0,150)}`));

let parsed;
try { parsed = JSON.parse(content.substring(fb,lb+1)); }
catch(e) {
  try { parsed = JSON.parse(content.substring(fb,lb+1).replace(/,\s*([}\]])/g,'$1')); }
  catch(e2) { return batchMeta.emailMetas.map(m => errResult(m, `Parse error: ${e.message}`)); }
}

const results = parsed.results || [];
console.log(`✅ Batch ${batchMeta.batchIndex+1}/${batchMeta.totalBatches}: ${results.length} results for ${batchMeta.emailMetas.length} emails`);

const STATUS_MAP = { application_confirmation:'Applied', rejection:'Rejected', positive_response:'Positive Response', not_job_related:'' };
const JOB_CLASSES = ['application_confirmation','rejection','positive_response'];
const PLATFORM_NAMES = ['smartrecruiters','softgarden','greenhouse','recruitee','onlyfy','personio','workday','lever','successfactors','bamboohr','icims','taleo','broadbean','workwise','hokify','join.com','stepstone','linkedin','indeed','xing','glassdoor','monster'];

function detectPlatform(from, ai) {
  const VALID = ['SmartRecruiters','Onlyfy','Personio','Workday','Lever','Greenhouse','SAP SuccessFactors','BambooHR','Recruitee','Softgarden','iCIMS','Oracle Taleo','Broadbean','LinkedIn','StepStone','Indeed','Xing','JOIN','Workwise','Direct'];
  if (ai && VALID.includes(ai)) return ai;
  const f = (from||'').toLowerCase();
  const MAP = [['smartrecruiters','SmartRecruiters'],['onlyfy','Onlyfy'],['personio','Personio'],['workday','Workday'],['lever.co','Lever'],['greenhouse','Greenhouse'],['successfactors','SAP SuccessFactors'],['bamboohr','BambooHR'],['recruitee','Recruitee'],['softgarden','Softgarden'],['icims','iCIMS'],['taleo','Oracle Taleo'],['broadbean','Broadbean'],['workwise','Workwise'],['linkedin','LinkedIn'],['stepstone','StepStone'],['indeed','Indeed'],['xing.com','Xing'],['join.com','JOIN']];
  for (const [k,v] of MAP) { if (f.includes(k)) return v; }
  return 'Direct';
}
function cleanCompany(name) {
  if (!name) return null;
  const n = name.trim();
  if (PLATFORM_NAMES.some(p => n.toLowerCase().includes(p))) return null;
  if (['unknown','not specified','n/a','none',''].includes(n.toLowerCase())) return null;
  return n;
}
function domainCompany(from) {
  const m = (from||'').match(/@([\w.-]+)/);
  if (!m) return null;
  const d = m[1].toLowerCase();
  if (PLATFORM_NAMES.some(p => d.includes(p))) return null;
  const SKIP = ['gmail.com','yahoo.com','hotmail.com','outlook.com','web.de','gmx.de','gmx.net'];
  if (SKIP.includes(d)) return null;
  const name = d.replace(/\.(com|de|io|net|org|eu|jobs|at|ch|fr|nl|co\.uk)$/,'').replace(/^(mail|email|reply|noreply|no-reply|notification|notifications|info|career|careers|recruiting|hr|jobs|talent|bewerbung|support|team|hello|pimsprod|donotreply)\./i,'').replace(/[-_.]/g,' ').trim();
  if (name.length < 2) return null;
  return name.split(' ').map(w=>w.charAt(0).toUpperCase()+w.slice(1)).join(' ');
}

// Map results (1-based from Gemini)
const resultMap = {};
for (const r of results) {
  const idx = (r.email_index||1) - 1;
  if (idx >= 0 && idx < batchMeta.emailMetas.length) resultMap[idx] = r;
}
if (Object.keys(resultMap).length===0 && results.length>0) {
  results.forEach((r,i) => { if (i < batchMeta.emailMetas.length) resultMap[i]=r; });
}

return batchMeta.emailMetas.map((meta, idx) => {
  const r = resultMap[idx];
  if (!r) { mark(meta.emailId); return errResult(meta, 'No Gemini result for this email'); }
  const cls        = JOB_CLASSES.includes(r.classification) ? r.classification : 'not_job_related';
  const isJob      = JOB_CLASSES.includes(cls);
  const status     = STATUS_MAP[cls] || '';
  const platform   = detectPlatform(meta.from, r.platform);
  const confidence = parseFloat(r.confidence) || 0;
  const company    = cleanCompany(r.company_name) || domainCompany(meta.from) || 'Unknown';
  mark(meta.emailId);
  const ICON = { application_confirmation:'📝', rejection:'❌', positive_response:'🎉', not_job_related:'⬛' };
  console.log(`  ${ICON[cls]||'❓'} [${idx+1}] ${cls}(${confidence.toFixed(2)}) | ${company} | "${(meta.subject||'').substring(0,40)}"`);
  return { json: {
    spreadsheetId: meta.spreadsheetId, logSheetId: String(meta.logSheetId||''),
    applicationsSheetId: String(meta.applicationsSheetId||''), config: meta.config,
    is_job_related: isJob, classification: cls,
    company_name: company, job_title: (r.job_title||'Not Specified').trim(),
    platform, status, confidence,
    reasoning: (r.reasoning||'').substring(0,200),
    email_subject: meta.subject, email_from: meta.from,
    email_date: meta.parsedDate, emailId: meta.emailId, threadId: meta.threadId
  } };
});

