const sheetRows  = $('📖 Read Applications').all().filter(i => i.json?.['Company Name'] && Object.keys(i.json).length > 1);
const emailData  = $input.first().json;
const ssId       = emailData.spreadsheetId || '';
const today      = emailData.email_date || new Date().toISOString().split('T')[0];
const threadId   = emailData.threadId || '';
const newStatus  = emailData.status || '';

console.log(`🔍 Dedup: "${emailData.company_name}" | "${emailData.job_title}" | ${newStatus} | rows:${sheetRows.length}`);

const skip = (reason) => [{ json: { action:'skip', spreadsheetId:ssId, reason } }];
if (!newStatus)  return skip('No status');
if (!ssId)       return skip('No spreadsheetId');

function normC(s) { return (s||'').toLowerCase().replace(/\b(gmbh|ag|inc|ltd|co\.|corp|se|kg|group|gruppe|holding|services|solutions|technologies|tech|software|germany|deutschland|europe)\b/gi,'').replace(/[^\wäöüß\s]/gi,'').replace(/\s+/g,' ').trim(); }
function normT(s) { return (s||'').toLowerCase().replace(/\(m\/w\/d\)|\(w\/m\/d\)|\(f\/m\/d\)|\(all genders\)|\(m\/f\/d\)|\(\*\)/gi,'').replace(/[^\wäöüß\s]/gi,'').replace(/\s+/g,' ').trim(); }
function cSim(a,b) {
  const na=normC(a),nb=normC(b); if(!na||!nb) return 0; if(na===nb) return 1; if(na.includes(nb)||nb.includes(na)) return 0.9;
  const wa=na.split(' ').filter(w=>w.length>2), wb=nb.split(' ').filter(w=>w.length>2);
  if(!wa.length||!wb.length) return 0;
  return wa.filter(w=>wb.some(x=>x===w||x.includes(w)||w.includes(x))).length/Math.max(wa.length,wb.length);
}
function tSim(a,b) {
  const na=normT(a),nb=normT(b); if(!na||!nb) return 0; if(na===nb) return 1; if(na.includes(nb)||nb.includes(na)) return 0.85;
  const wa=na.split(' ').filter(w=>w.length>3), wb=nb.split(' ').filter(w=>w.length>3);
  if(!wa.length||!wb.length) return 0;
  return wa.filter(w=>wb.includes(w)).length/Math.max(wa.length,wb.length);
}

const PRIORITY = { 'Applied':1,'Positive Response':2,'Interview':3,'Offer':100,'Rejected':99 };

// Thread match
let bestMatch = null;
if (threadId) {
  for (const ri of sheetRows) {
    const row = ri.json;
    if ((row['Thread ID']||'') !== threadId) continue;
    const et=normT(row['Job Title']||''), nt=normT(emailData.job_title||'');
    if (et && nt && et!=='not specified' && nt!=='not specified' && tSim(et,nt)<0.25) continue;
    bestMatch = row;
    console.log(`  🔗 Thread match: ${row['Company Name']} | ${row['Status']}`);
    break;
  }
}

// Fuzzy match
if (!bestMatch) {
  let best=0;
  for (const ri of sheetRows) {
    const row=ri.json, cs=cSim(emailData.company_name,row['Company Name']||'');
    if (cs<0.5) continue;
    const nt=emailData.job_title, et=row['Job Title']||'';
    let score = cs;
    if (nt&&nt!=='Not Specified'&&et&&et!=='Not Specified') {
      const ts=tSim(nt,et); score=(ts<0.2&&cs<0.95)?0:(cs*0.4+ts*0.6);
    } else { score=cs*0.75; }
    if (score>best&&score>=0.4) { best=score; bestMatch=row; }
  }
  if (bestMatch) console.log(`  🔍 Fuzzy: ${bestMatch['Company Name']} (${(bestMatch._score||0).toFixed?.(2)})`);
}

if (bestMatch) {
  const cur=bestMatch['Status']||'Applied';
  if (cur===newStatus) return skip(`Already ${cur}`);
  const cp=PRIORITY[cur]||0, np=PRIORITY[newStatus]||0;
  const upgrade = np>cp || (newStatus==='Rejected'&&cur!=='Offer');
  if (upgrade) {
    const updTitle=(bestMatch['Job Title']==='Not Specified'&&emailData.job_title!=='Not Specified')?emailData.job_title:bestMatch['Job Title'];
    console.log(`  ⬆️ Upgrade: "${cur}" → "${newStatus}"`);
    return [{ json: { action:'update', spreadsheetId:ssId, 'Company Name':bestMatch['Company Name'], 'Job Title':updTitle, 'Status':newStatus, 'Last Updated':today, '_matchThreadId':bestMatch['Thread ID']||'', 'Processed At':new Date().toISOString(), 'Notes':`${cur}→${newStatus} | ${(emailData.email_subject||'').substring(0,100)}` } }];
  }
  return skip(`Protected: ${cur}`);
}

console.log(`  ✨ New: ${emailData.company_name}`);
return [{ json: { action:'add', spreadsheetId:ssId, 'Date Applied':today, 'Company Name':emailData.company_name, 'Job Title':emailData.job_title, 'Platform':emailData.platform, 'Status':newStatus, 'Email Subject':(emailData.email_subject||'').substring(0,150), 'Email From':emailData.email_from, 'Last Updated':today, 'Notes':(emailData.reasoning||'').substring(0,150), 'Thread ID':threadId, 'Processed At':new Date().toISOString() } }];

